/**
 * platform-review-consolidate.js
 *
 * Merges per-persona finding JSON files into a consolidated markdown report
 * and a backlog-candidate JSON array.
 *
 * Hybrid approach: The script handles merging, deduplication (keyword-based
 * first pass), severity sorting, report formatting, and backlog schema mapping.
 * Claude handles semantic overlap classification (New/Expand/Duplicate) by
 * reading the script's output alongside the existing backlog.
 *
 * Usage:
 *   node scripts/platform-review-consolidate.js --checkpoint-dir docs/platform-review/2026-03-26 [options]
 *
 * Options:
 *   --checkpoint-dir <path>    Directory containing *.findings.json files (required)
 *   --severity-threshold <lvl> Minimum severity for backlog candidates: Critical|High|Medium|Low (default: Medium)
 *   --output <path>            Output report path (default: <checkpoint-dir>/platform-review-report.md)
 *   --backlog-json <path>      Output backlog candidates JSON (default: <checkpoint-dir>/backlog-candidates.json)
 *   --backlog-path <path>      Path to existing backlog YAML for overlap context (default: docs/backlog/backlog.yaml)
 *   --project-name <name>      Project name for report headers (default: none)
 *   --target-orgs <orgs>       Target org description for report header (default: auto-detected from findings)
 *   --json                     Output summary as JSON instead of text
 *   --help                     Show this help message
 *
 * Exit codes: 0 = success, 1 = validation error, 2 = file error
 *
 * Input format (*.findings.json):
 *   {
 *     "persona": "Security Analyst",
 *     "completed_at": "2026-03-26T...",
 *     "summary": "...",
 *     "findings": [
 *       {
 *         "id": "SEC-001",
 *         "title": "...",
 *         "severity": "Critical|High|Medium|Low",
 *         "category": "...",
 *         "effort": "S|M|L|XL",
 *         "complexity": "Low|Medium|High",
 *         "description": "...",
 *         "recommendation": "...",
 *         "evidence": "...",
 *         "tags": ["tag1", "tag2"],
 *         "backlog_candidate": true|false
 *       }
 *     ]
 *   }
 */

"use strict";

const fs = require("fs");
const path = require("path");

const REPO_ROOT = path.join(__dirname, "..");

const SEVERITY_ORDER = ["Critical", "High", "Medium", "Low"];
const SEVERITY_TO_PRIORITY = {
  Critical: "P1",
  High: "P2",
  Medium: "P3",
  Low: "P4",
};

// Default persona ordering and labels — customize for your project
const PERSONA_ORDER = [
  "security",
  "qa",
  "coding-standards",
  "docs",
  "agentforce",
  "analytics",
  "devops",
];

const PERSONA_LABELS = {
  security: "Security Analyst",
  qa: "QA Lead",
  "coding-standards": "Coding Standards Manager",
  docs: "Documentation Analyst",
  agentforce: "Agentforce Expert",
  analytics: "Analytics SME",
  devops: "DevOps Expert",
};

// ---------------------------------------------------------------------------
// Argument parsing
// ---------------------------------------------------------------------------

function parseArgs(argv) {
  const args = {};
  let i = 2;
  while (i < argv.length) {
    const key = argv[i];
    if (key === "--help") {
      printHelp();
      process.exit(0);
    }
    if (key.startsWith("--")) {
      const name = key.slice(2);
      if (name === "json") {
        args[name] = true;
        i++;
      } else {
        if (i + 1 >= argv.length) {
          console.error(`Error: --${name} requires a value`);
          process.exit(1);
        }
        args[name] = argv[i + 1];
        i += 2;
      }
    } else {
      console.error(`Error: unexpected argument "${key}"`);
      process.exit(1);
    }
  }
  return args;
}

