// ---------------------------------------------------------------------------
// Keyword similarity (used for cross-persona deduplication only)
// ---------------------------------------------------------------------------

/**
 * Compute simple word-overlap similarity between two strings (0-1).
 * Used ONLY for cross-persona deduplication (same finding from different personas).
 * NOT used for backlog overlap detection — that is deferred to Claude (semantic matching).
 */
function wordSimilarity(a, b) {
  if (!a || !b) return 0;
  const wordsA = new Set(
    a
      .toLowerCase()
      .replace(/[^a-z0-9\s]/g, "")
      .split(/\s+/)
      .filter(Boolean)
  );
  const wordsB = new Set(
    b
      .toLowerCase()
      .replace(/[^a-z0-9\s]/g, "")
      .split(/\s+/)
      .filter(Boolean)
  );
  if (wordsA.size === 0 || wordsB.size === 0) return 0;
  let overlap = 0;
  for (const w of wordsA) {
    if (wordsB.has(w)) overlap++;
  }
  const union = new Set([...wordsA, ...wordsB]).size;
  return overlap / union; // Jaccard similarity
}

// ---------------------------------------------------------------------------
// Deduplication across personas
// ---------------------------------------------------------------------------

function deduplicateFindings(allFindings) {
  const deduplicated = [];
  const merged = new Set();

  for (let i = 0; i < allFindings.length; i++) {
    if (merged.has(i)) continue;
    const finding = { ...allFindings[i], cross_references: [] };

    for (let j = i + 1; j < allFindings.length; j++) {
      if (merged.has(j)) continue;
      const other = allFindings[j];

      // Only deduplicate across different personas
      if (finding.persona === other.persona) continue;

      const sim = wordSimilarity(
        finding.title + " " + finding.description,
        other.title + " " + other.description
      );
      if (sim >= 0.5) {
        const findingSev = SEVERITY_ORDER.indexOf(finding.severity);
        const otherSev = SEVERITY_ORDER.indexOf(other.severity);
        if (otherSev < findingSev) {
          finding.severity = other.severity;
          finding.description = other.description;
          finding.recommendation = other.recommendation;
        }
        finding.cross_references.push(
          `${other.id} (${PERSONA_LABELS[other.persona] || other.persona})`
        );
        merged.add(j);
      }
    }

    deduplicated.push(finding);
  }

  return deduplicated;
}

// ---------------------------------------------------------------------------
// Report generation
// ---------------------------------------------------------------------------

function generateReport(findings, personaData, date, targetOrgs, projectName) {
  const lines = [];
  const bySeverity = {};
  for (const sev of SEVERITY_ORDER) {
    bySeverity[sev] = findings.filter((f) => f.severity === sev);
  }

  const totalCount = findings.length;
  const critCount = bySeverity["Critical"].length;
  const highCount = bySeverity["High"].length;
  const medCount = bySeverity["Medium"].length;
  const lowCount = bySeverity["Low"].length;

  const title = projectName
    ? `# ${projectName} — Platform Review Report`
    : "# Platform Review Report";
  lines.push(title);
  lines.push("");
  lines.push(`**Date:** ${date}`);
  lines.push(
    `**Personas run:** ${Object.keys(personaData)
      .map((k) => PERSONA_LABELS[k] || k)
      .join(", ")}`
  );
  if (targetOrgs) {
    lines.push(`**Target orgs:** ${targetOrgs}`);
  }
  lines.push("");

  // Executive Summary
  lines.push("## Executive Summary");
  lines.push("");
  lines.push(
    `This platform review identified **${totalCount} findings** across ${Object.keys(personaData).length} expert personas:`
  );
  lines.push("");
  lines.push(`- **Critical:** ${critCount}`);
  lines.push(`- **High:** ${highCount}`);
  lines.push(`- **Medium:** ${medCount}`);
  lines.push(`- **Low:** ${lowCount}`);
  lines.push("");

  // Top 5 recommendations
  const topFindings = findings
    .sort(
      (a, b) =>
        SEVERITY_ORDER.indexOf(a.severity) - SEVERITY_ORDER.indexOf(b.severity)
    )
    .slice(0, 5);

  if (topFindings.length > 0) {
    lines.push("### Top Recommendations");
    lines.push("");
    for (let i = 0; i < topFindings.length; i++) {
      lines.push(
        `${i + 1}. **${topFindings[i].title}** (${topFindings[i].severity}) — ${topFindings[i].recommendation}`
      );
    }
    lines.push("");
  }

  // Findings by Severity
  lines.push("## Findings by Severity");
  lines.push("");

  for (const sev of SEVERITY_ORDER) {
    const items = bySeverity[sev];
    if (items.length === 0) continue;

    lines.push(`### ${sev} (${items.length})`);
    lines.push("");
    lines.push("| ID | Persona | Title | Effort | Category |");
    lines.push("| --- | --- | --- | --- | --- |");
    for (const f of items) {
      const persona = PERSONA_LABELS[f.persona] || f.persona;
      const title = (f.title || "").replace(/\|/g, "\\|");
      lines.push(
        `| ${f.id} | ${persona} | ${title} | ${f.effort} | ${f.category} |`
      );
    }
    lines.push("");
  }

  // Detailed Findings by Persona
  lines.push("## Detailed Findings by Persona");
  lines.push("");

  for (const key of PERSONA_ORDER) {
    if (!personaData[key]) continue;
    const pd = personaData[key];
    const label = PERSONA_LABELS[key] || key;

    lines.push(`### ${label}`);
    lines.push("");
    lines.push(`> ${pd.summary || "No summary provided."}`);
    lines.push("");

    const personaFindings = findings.filter((f) => f.persona === key);
    for (const f of personaFindings) {
      lines.push(`#### ${f.id}: ${f.title}`);
      lines.push("");
      lines.push(`- **Severity:** ${f.severity}`);
      lines.push(`- **Category:** ${f.category}`);
      lines.push(`- **Effort:** ${f.effort} | **Complexity:** ${f.complexity}`);
      lines.push(`- **Tags:** ${(f.tags || []).join(", ") || "none"}`);
      if (f.evidence) {
        lines.push(`- **Evidence:** ${f.evidence}`);
      }
      lines.push("");
      lines.push(f.description);
      lines.push("");
      lines.push(`**Recommendation:** ${f.recommendation}`);
      if (f.cross_references && f.cross_references.length > 0) {
        lines.push("");
        lines.push(`**Also flagged by:** ${f.cross_references.join(", ")}`);
      }
      lines.push("");
    }
  }

  // Cross-Cutting Themes
  const crossCutFindings = findings.filter(
    (f) => f.cross_references && f.cross_references.length > 0
  );
  if (crossCutFindings.length > 0) {
    lines.push("## Cross-Cutting Themes");
    lines.push("");
    lines.push(
      "The following findings were flagged by multiple personas, indicating systemic patterns:"
    );
    lines.push("");
    for (const f of crossCutFindings) {
      lines.push(
        `- **${f.title}** (${f.id}) — flagged by ${f.cross_references.join(", ")}`
      );
    }
    lines.push("");
  }

  // Prioritized Recommendations (top 10)
  lines.push("## Prioritized Recommendations");
  lines.push("");

  const top10 = findings
    .sort((a, b) => {
      const sevDiff =
        SEVERITY_ORDER.indexOf(a.severity) - SEVERITY_ORDER.indexOf(b.severity);
      if (sevDiff !== 0) return sevDiff;
      const effortOrder = ["S", "M", "L", "XL"];
      return effortOrder.indexOf(a.effort) - effortOrder.indexOf(b.effort);
    })
    .slice(0, 10);

  lines.push("| Rank | ID | Title | Severity | Effort | Category |");
  lines.push("| --- | --- | --- | --- | --- | --- |");
  for (let i = 0; i < top10.length; i++) {
    const f = top10[i];
    const title = (f.title || "").replace(/\|/g, "\\|");
    lines.push(
      `| ${i + 1} | ${f.id} | ${title} | ${f.severity} | ${f.effort} | ${f.category} |`
    );
  }
  lines.push("");

  // Appendix
  lines.push("## Appendix: Scope & Methodology");
  lines.push("");
  lines.push("Each persona examined targeted areas of the platform:");
  lines.push("");
  for (const key of PERSONA_ORDER) {
    if (!personaData[key]) continue;
    const pd = personaData[key];
    lines.push(
      `- **${PERSONA_LABELS[key]}:** ${pd.summary || "See findings above."}`
    );
  }
  lines.push("");

  return lines.join("\n");
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

function main() {
  const args = parseArgs(process.argv);

  if (!args["checkpoint-dir"]) {
    console.error("Error: --checkpoint-dir is required");
    console.error(
      "Usage: node scripts/platform-review-consolidate.js --checkpoint-dir <path>"
    );
    console.error("Run with --help for full usage details.");
    process.exit(1);
  }

  const checkpointDir = path.resolve(REPO_ROOT, args["checkpoint-dir"]);
  if (!fs.existsSync(checkpointDir)) {
    console.error(
      `Error: checkpoint directory does not exist: ${checkpointDir}`
    );
    process.exit(2);
  }

  const severityThreshold = args["severity-threshold"] || "Medium";
  if (!SEVERITY_ORDER.includes(severityThreshold)) {
    console.error(
      `Error: invalid severity-threshold "${severityThreshold}". Must be one of: ${SEVERITY_ORDER.join(", ")}`
    );
    process.exit(1);
  }
  const thresholdIndex = SEVERITY_ORDER.indexOf(severityThreshold);

  const outputPath = args.output
    ? path.resolve(REPO_ROOT, args.output)
    : path.join(checkpointDir, "platform-review-report.md");

  const backlogJsonPath = args["backlog-json"]
    ? path.resolve(REPO_ROOT, args["backlog-json"])
    : path.join(checkpointDir, "backlog-candidates.json");

  const backlogYamlPath = args["backlog-path"]
    ? path.resolve(REPO_ROOT, args["backlog-path"])
    : path.join(REPO_ROOT, "docs", "backlog", "backlog.yaml");

  const projectName = args["project-name"] || null;
  const targetOrgs = args["target-orgs"] || null;

  // --- Load persona findings ---
  const personaData = {};
  const allFindings = [];

  const files = fs
    .readdirSync(checkpointDir)
    .filter((f) => f.endsWith(".findings.json"));
  if (files.length === 0) {
    console.error(
      "Error: no *.findings.json files found in checkpoint directory"
    );
    process.exit(2);
  }

  for (const file of files) {
    const filePath = path.join(checkpointDir, file);
    let data;
    try {
      data = JSON.parse(fs.readFileSync(filePath, "utf8"));
    } catch (err) {
      console.error(`Error: cannot parse ${file} — ${err.message}`);
      process.exit(2);
    }

    const personaKey = file.replace(".findings.json", "");
    personaData[personaKey] = {
      persona: data.persona || PERSONA_LABELS[personaKey] || personaKey,
      completed_at: data.completed_at,
      summary: data.summary || "",
    };

    for (const finding of data.findings || []) {
      allFindings.push({
        ...finding,
        persona: personaKey,
      });
    }
  }

  console.log(
    `Loaded ${allFindings.length} findings from ${files.length} persona file(s).`
  );

  // --- Deduplicate ---
  const deduplicated = deduplicateFindings(allFindings);
  const deduplicatedCount = allFindings.length - deduplicated.length;
  if (deduplicatedCount > 0) {
    console.log(`Deduplicated ${deduplicatedCount} cross-persona duplicates.`);
  }

  // --- Load backlog context for overlap classification ---
  let backlogContext = [];
  if (fs.existsSync(backlogYamlPath)) {
    try {
      // Try to load js-yaml if available; fall back to basic parsing
      let yamlLoad;
      try {
        yamlLoad = require("js-yaml").load;
      } catch (e) {
        yamlLoad = null;
      }

      if (yamlLoad) {
        const backlogRaw = fs.readFileSync(backlogYamlPath, "utf8");
        const backlogData = yamlLoad(backlogRaw);
        const items = (backlogData && backlogData.items) || [];
        backlogContext = items.map((item) => ({
          id: item.id,
          title: item.title,
          description: (item.description || "").slice(0, 300).trim(),
          category: item.category,
          status: item.status,
          tags: item.tags || [],
        }));
      } else {
        console.error(
          "Warning: js-yaml not installed — skipping backlog context loading. Install with: npm install js-yaml"
        );
      }
    } catch (err) {
      console.error(`Warning: cannot read backlog YAML — ${err.message}`);
    }
  } else {
    console.log(
      "Note: No backlog YAML found at " +
        path.relative(REPO_ROOT, backlogYamlPath) +
        " — skipping overlap context."
    );
  }

  // --- Build backlog candidates (schema-mapped, unclassified) ---
  const candidates = deduplicated
    .filter((f) => f.backlog_candidate === true)
    .filter((f) => SEVERITY_ORDER.indexOf(f.severity) <= thresholdIndex);

  const mapped = candidates.map((f) => ({
    finding_id: f.id,
    title: f.title,
    description: `${f.description}\n\nRecommendation: ${f.recommendation}`,
    category: f.category,
    priority: SEVERITY_TO_PRIORITY[f.severity] || "P3",
    effort: f.effort,
    complexity: f.complexity,
    tags: f.tags || [],
    source: "claude-session",
    severity: f.severity,
    persona: PERSONA_LABELS[f.persona] || f.persona,
  }));

  console.log(
    `Backlog candidates: ${mapped.length} (>= ${severityThreshold}). Classification deferred to Claude.`
  );

  // --- Extract date from checkpoint dir name ---
  const date = path.basename(checkpointDir);

  // --- Generate report ---
  const report = generateReport(
    deduplicated,
    personaData,
    date,
    targetOrgs,
    projectName
  );

  // --- Write outputs ---
  try {
    fs.writeFileSync(outputPath, report, "utf8");
    console.log(`Report written: ${path.relative(REPO_ROOT, outputPath)}`);
  } catch (err) {
    console.error(`Error: cannot write report — ${err.message}`);
    process.exit(2);
  }

  // --- Write backlog candidates + context ---
  const backlogOutput = {
    _meta: {
      description:
        "Backlog candidates from platform review. Script handled schema mapping and severity filtering. Claude should classify each candidate as New/Expand/Duplicate by comparing semantically against existing_backlog_items.",
      severity_threshold: severityThreshold,
      generated_at: new Date().toISOString(),
    },
    candidates: mapped,
    existing_backlog_items: backlogContext,
  };

  try {
    fs.writeFileSync(
      backlogJsonPath,
      JSON.stringify(backlogOutput, null, 2),
      "utf8"
    );
    console.log(
      `Backlog candidates written: ${path.relative(REPO_ROOT, backlogJsonPath)}`
    );
  } catch (err) {
    console.error(`Error: cannot write backlog candidates — ${err.message}`);
    process.exit(2);
  }

  // --- Summary output ---
  if (args.json) {
    const summary = {
      total_findings: deduplicated.length,
      deduplicated: deduplicatedCount,
      by_severity: {},
      backlog_candidates: mapped.length,
      existing_backlog_items: backlogContext.length,
      personas_processed: Object.keys(personaData),
      output_report: path.relative(REPO_ROOT, outputPath),
      output_backlog_json: path.relative(REPO_ROOT, backlogJsonPath),
    };
    for (const sev of SEVERITY_ORDER) {
      summary.by_severity[sev] = deduplicated.filter(
        (f) => f.severity === sev
      ).length;
    }
    console.log(JSON.stringify(summary, null, 2));
  } else {
    console.log("\n--- Consolidation Summary ---");
    console.log(`Total findings: ${deduplicated.length}`);
    for (const sev of SEVERITY_ORDER) {
      const count = deduplicated.filter((f) => f.severity === sev).length;
      if (count > 0) console.log(`  ${sev}: ${count}`);
    }
    console.log(`Cross-persona deduplication: ${deduplicatedCount} merged`);
    console.log(
      `Backlog candidates (>= ${severityThreshold}): ${mapped.length}`
    );
    console.log(
      `Existing backlog items loaded for overlap classification: ${backlogContext.length}`
    );
  }

  process.exit(0);
}

main();
